import React from 'react';
import CIcon from '@coreui/icons-react';
import {
  cilAccountLogout,
  cilBorderAll,
  cilUser,
} from '@coreui/icons';
import { CNavItem } from '@coreui/react';

const createNavItem = (name, to, icon) => ({
  component: CNavItem,
  name,
  to,
  icon: <CIcon icon={icon} customClassName="nav-icon" />,
});

const menuList = [
  createNavItem('Dashboard', '/dashboard', cilBorderAll),
  createNavItem('Colleges', '/colleges', cilUser),
  createNavItem('Logout', '/logout', cilAccountLogout),
];

export default menuList;
